type token = TIdent of string | TInt of int | TPct of int | TMinus | TLArrow | TRArrow | TLParen | TRParen | TLBrace | TRBrace | TComma | TUnderscore | THash of string | TLiteral of string | TUnknown of int | TEOF | TMint
let token_name t = match t with TIdent s -> "ident:" ^ s | TInt n -> "int" | TPct n -> "pct" | TMinus -> "minus" | TLArrow -> "larrow" | TRArrow -> "rarrow" | TLParen -> "lparen" | TRParen -> "rparen" | TLBrace -> "lbrace" | TRBrace -> "rbrace" | TComma -> "comma" | TUnderscore -> "slot" | THash s -> "hash" | TLiteral s -> "lit" | TUnknown n -> "unknown" | TEOF -> "eof" | TMint -> "mint"
